class WorkDiary{constructor(){this.storageKey='princeWorkDiaries';this.diaries=this.loadDiaries();this.init();}init(){this.setupEventListeners();this.renderDiaries();this.updateStatistics();}loadDiaries(){try{const saved=localStorage.getItem(this.storageKey);if(saved){return JSON.parse(saved);}}catch(error){console.error('加载日记失败:',error);}return[{id:1,date:'2026-04-05',title:'网站项目完成与反思',content:'今天完成了个人网站的建设工作，包括首页、关于我、我的日常、我的相册、我的工作和工作日记六个页面。\n\n收获：\n• 掌握了响应式网页设计的基本原理\n• 实践了JavaScript与HTML/CSS的交互\n• 学习了图片懒加载和模态框的实现\n• 理解了用户界面设计的重要性\n\n反思：在时间管理上还有提升空间，需要更好地规划开发进度。',tags:['项目进展','学习心得','技术实践'],createdAt:new Date().toISOString()},{id:2,date:'2026-04-04',title:'团队协作优化会议',content:'主持了团队协作流程优化会议，讨论了当前工作流程中的瓶颈和改进方案。\n\n讨论要点：\n• 沟通效率提升：建议使用更结构化的会议议程\n• 任务分配优化：引入更清晰的责任矩阵\n• 工具整合：评估新的协作工具\n• 反馈机制：建立更及时的反馈循环\n\n行动计划：下周开始试行新的会议模板和任务分配流程。',tags:['团队管理','流程优化','会议记录'],createdAt:new Date().toISOString()},{id:3,date:'2026-04-03',title:'技术难题解决记录',content:'遇到了一个复杂的技术问题：系统集成时的数据同步延迟问题。\n\n问题分析：\n• 根本原因：数据库连接池配置不当\n• 影响范围：数据同步延迟达5-10分钟\n• 紧急程度：高（影响业务决策）\n\n解决方案：\n• 调整数据库连接池参数\n• 增加缓存层减少数据库压力\n• 优化数据同步算法\n• 添加监控告警机制\n\n结果：数据同步延迟降低到30秒以内，问题得到解决。',tags:['问题解决','技术优化','系统集成'],createdAt:new Date().toISOString()}];}saveDiaries(){try{localStorage.setItem(this.storageKey,JSON.stringify(this.diaries));}catch(error){console.error('保存日记失败:',error);}}setupEventListeners(){const form=document.getElementById('diaryForm');if(form){form.addEventListener('submit',(e)=>this.handleSubmit(e));}const dateInput=document.getElementById('diaryDate');if(dateInput){const today=new Date().toISOString().split('T')[0];dateInput.value=today;dateInput.max=today;}}handleSubmit(event){event.preventDefault();const dateInput=document.getElementById('diaryDate');const titleInput=document.getElementById('diaryTitle');const contentInput=document.getElementById('diaryContent');const tagsInput=document.getElementById('diaryTags');if(!dateInput.value||!titleInput.value||!contentInput.value){alert('请填写所有必填字段！');return;}const newDiary={id:Date.now(),date:dateInput.value,title:titleInput.value,content:contentInput.value,tags:tagsInput.value?tagsInput.value.split(',').map(tag=>tag.trim()).filter(tag=>tag):[],createdAt:new Date().toISOString()};this.diaries.unshift(newDiary);this.saveDiaries();this.renderDiaries();this.updateStatistics();this.clearForm();this.showMessage('日记保存成功！','success');}clearForm(){const form=document.getElementById('diaryForm');if(form){form.reset();const dateInput=document.getElementById('diaryDate');if(dateInput){const today=new Date().toISOString().split('T')[0];dateInput.value=today;}}}showMessage(message,type='info'){const existingMessage=document.querySelector('.diary-message');if(existingMessage){existingMessage.remove();}const messageDiv=document.createElement('div');messageDiv.className=`diary-message diary-message-${type}`;messageDiv.innerHTML=`<i class="fas fa-${type==='success'?'check-circle':'info-circle'}"></i><span>${message}</span><button onclick="this.parentElement.remove()" style="margin-left:auto;background:none;border:none;color:inherit;cursor:pointer;"><i class="fas fa-times"></i></button>`;const formSection=document.querySelector('.content-section:nth-child(1)');if(formSection){formSection.appendChild(messageDiv);}setTimeout(()=>{if(messageDiv.parentElement){messageDiv.remove();}},3000);}renderDiaries(filteredDiaries=null){const diaryList=document.getElementById('diaryList');const noDiariesMessage=document.getElementById('noDiariesMessage');if(!diaryList)return;const diariesToRender=filteredDiaries||this.diaries;if(diariesToRender.length===0){diaryList.innerHTML='';if(noDiariesMessage){noDiariesMessage.style.display='block';}return;}if(noDiariesMessage){noDiariesMessage.style.display='none';}diaryList.innerHTML='';diariesToRender.forEach(diary=>{const diaryElement=this.createDiaryElement(diary);diaryList.appendChild(diaryElement);});this.updateDiaryCount(diariesToRender.length);}createDiaryElement(diary){const diaryElement=document.createElement('div');diaryElement.className='diary-entry';diaryElement.dataset.id=diary.id;const dateObj=new Date(diary.date);const formattedDate=dateObj.toLocaleDateString('zh-CN',{year:'numeric',month:'long',day:'numeric',weekday:'long'});const formattedContent=diary.content.replace(/\n/g,'<br>').replace(/•/g,'•');diaryElement.innerHTML=`<div class="diary-date"><i class="far fa-calendar"></i>${formattedDate}<button class="delete-diary" onclick="workDiary.deleteDiary(${diary.id})" style="float:right;background:none;border:none;color:var(--text-light);cursor:pointer;font-size:0.9rem;"><i class="fas fa-trash"></i>删除</button></div><div class="diary-title">${this.escapeHtml(diary.title)}</div><div class="diary-content">${formattedContent}</div><div class="diary-tags">${diary.tags.map(tag=>`<span class="tag">${this.escapeHtml(tag)}</span>`).join('')}</div>`;return diaryElement;}deleteDiary(id){if(confirm('确定要删除这篇日记吗？此操作不可撤销。')){this.diaries=this.diaries.filter(diary=>diary.id!==id);this.saveDiaries();this.renderDiaries();this.updateStatistics();this.showMessage('日记已删除','info');}}filterDiaries(){const monthFilter=document.getElementById('monthFilter');const tagFilter=document.getElementById('tagFilter');const searchFilter=document.getElementById('searchFilter');let filtered=[...this.diaries];if(monthFilter&&monthFilter.value!=='all'){filtered=filtered.filter(diary=>diary.date.startsWith(monthFilter.value));}if(tagFilter&&tagFilter.value!=='all'){filtered=filtered.filter(diary=>diary.tags.includes(tagFilter.value));}if(searchFilter&&searchFilter.value.trim()){const searchTerm=searchFilter.value.toLowerCase().trim();filtered=filtered.filter(diary=>diary.title.toLowerCase().includes(searchTerm)||diary.content.toLowerCase().includes(searchTerm)||diary.tags.some(tag=>tag.toLowerCase().includes(searchTerm)));}this.renderDiaries(filtered);}updateDiaryCount(count){const countElement=document.getElementById('diaryCount');if(countElement){countElement.textContent=`共 ${count}篇日记`;}}updateStatistics(){const totalCount=document.getElementById('totalCount');if(totalCount){totalCount.textContent=this.diaries.length;}const monthlyCount=document.getElementById('monthlyCount');if(monthlyCount){const currentMonth=new Date().toISOString().slice(0,7);const monthlyDiaries=this.diaries.filter(diary=>diary.date.startsWith(currentMonth));monthlyCount.textContent=monthlyDiaries.length;}this.updateTagCloud();}updateTagCloud(){const tagCloud=document.getElementById('tagCloud');if(!tagCloud)return;const tagCounts={};this.diaries.forEach(diary=>{diary.tags.forEach(tag=>{tagCounts[tag]=(tagCounts[tag]||0)+1;});});const sortedTags=Object.entries(tagCounts).sort((a,b)=>b[1]-a[1]).slice(0,10);tagCloud.innerHTML=sortedTags.map(([tag,count])=>{const maxCount=Math.max(...Object.values(tagCounts));const minFontSize=0.9;const maxFontSize=1.5;const fontSize=minFontSize+(count/maxCount)*(maxFontSize-minFontSize);return `<span class="tag" style="font-size:${fontSize}em;cursor:pointer;" onclick="document.getElementById('tagFilter').value='${tag}';workDiary.filterDiaries();">${this.escapeHtml(tag)}</span>`;}).join(' ');}exportDiaries(){const dataStr=JSON.stringify(this.diaries,null,2);const dataUri='data:application/json;charset=utf-8,'+encodeURIComponent(dataStr);const exportFileDefaultName=`工作日记_${new Date().toISOString().slice(0,10)}.json`;const linkElement=document.createElement('a');linkElement.setAttribute('href',dataUri);linkElement.setAttribute('download',exportFileDefaultName);linkElement.click();this.showMessage('日记已导出为JSON文件','success');}escapeHtml(text){const div=document.createElement('div');div.textContent=text;return div.innerHTML;}}function filterDiaries(){if(window.workDiary){window.workDiary.filterDiaries();}}function clearForm(){if(window.workDiary){window.workDiary.clearForm();}}function exportDiaries(){if(window.workDiary){window.workDiary.exportDiaries();}}document.addEventListener('DOMContentLoaded',function(){window.workDiary=new WorkDiary();const messageStyles=`<style>.diary-message{padding:1rem;margin:1rem 0;border-radius:var(--border-radius);display:flex;align-items:center;gap:0.5rem;animation:slideIn 0.3s ease;}.diary-message-success{background-color:rgba(76,175,80,0.1);color:#2e7d32;border-left:4px solid #4caf50;}.diary-message-info{background-color:rgba(33,150,243,0.1);color:#1565c0;border-left:4px solid #2196f3;}.diary-tags{margin-top:1rem;display:flex;flex-wrap:wrap;gap:0.5rem;}.tag{background-color:rgba(139,69,19,0.1);color:var(--primary-color);padding:0.3rem 0.8rem;border-radius:20px;font-size:0.9rem;display:inline-block;}.delete-diary:hover{color:#f44336!important;}@keyframes slideIn{from{opacity:0;transform:translateY(-10px);}to{opacity:1;transform:translateY(0);}}</style>`;document.head.insertAdjacentHTML('beforeend',messageStyles);});